SELECT AVG(app_count) AS overall_avg_applications_per_posting
FROM (
  SELECT posting_id, COUNT(*) AS app_count
  FROM applications
  GROUP BY posting_id
);

SELECT AVG(application_count) AS average_applications_per_posting
FROM (
    SELECT posting_id, COUNT(*) AS application_count
    FROM applications
    GROUP BY posting_id
) AS app_counts;
